#![allow(clippy::unwrap_used, clippy::expect_used, clippy::doc_markdown)]

use std::fs;
use std::process::Command;
use tempfile::TempDir;

fn build_fixture(root: &std::path::Path) {
    let mem = root.join("memories").join("user");
    fs::create_dir_all(&mem).unwrap();
    for id in ["01AAA", "01BBB"] {
        fs::write(
            mem.join(format!("{id}.md")),
            format!("---\nid: {id}\nkind: semantic\nsubject: user\n---\nbody\n"),
        )
        .unwrap();
    }
    // Build an index DB with only 01AAA — 01BBB is orphaned on disk.
    let idx = root.join("index");
    fs::create_dir_all(&idx).unwrap();
    let db = idx.join("recall.sqlite");
    let path_str = mem.join("01AAA.md").to_string_lossy().to_string();
    let sql = format!(
        "CREATE TABLE memories_meta (id TEXT PRIMARY KEY, kind TEXT, subject TEXT, path TEXT, embedding_id TEXT);
INSERT INTO memories_meta VALUES ('01AAA','semantic','user','{path_str}',NULL);",
    );
    let _ = Command::new("sqlite3").arg(&db).arg(&sql).output().unwrap();
}

#[test]
fn acceptance_ac4() {
    let root = TempDir::new().unwrap();
    build_fixture(root.path());

    let bin = env!("CARGO_BIN_EXE_recall-doctor");
    let out = Command::new(bin)
        .args(["--root"])
        .arg(root.path())
        .args(["--format", "json"])
        .output()
        .unwrap();
    let json: serde_json::Value = serde_json::from_slice(&out.stdout).unwrap();
    let orphans: Vec<&str> = json["orphans"].as_array().unwrap().iter().map(|v| v.as_str().unwrap()).collect();
    assert_eq!(orphans, vec!["01BBB"]);
}
